mapper.select:
SELECT * FROM (SELECT * , (CC.cash_balance + CC.totalRevenue) AS totalAsset ,RANK() over (PARTITION BY CC.totalRevenueRate) AS userRevenueRank
FROM (SELECT UC.USER_SEQ , U.USER_ID , U.USER_NAME , UC.CASH_BALANCE , BB.totalRevenueRate AS totalRevenueRate , BB.totalAsset AS totalRevenue FROM USER_ACCOUNT UC LEFT OUTER JOIN (SELECT AA.USER_SEQ , AA.buySum AS totalBuy , AA.sellSum AS totalSell , CASE WHEN buySum = 0 THEN 0 ELSE ROUND(((sellSum - buySum) / buySum) * 100, 2) END AS totalRevenueRate , (sellSum - buySum) AS totalAsset FROM (SELECT USER_SEQ, SUM(CASE WHEN TRADE_TYPE = 'Y' THEN TRADE_PRICE ELSE 0 END) AS buySum, SUM(CASE WHEN TRADE_TYPE = 'N' THEN TRADE_PRICE ELSE 0 END) AS sellSum FROM MOCK_TRADE GROUP BY USER_SEQ) AA) BB ON UC.USER_SEQ = BB.USER_SEQ
LEFT OUTER JOIN USERS U ON UC.USER_SEQ = U.USER_SEQ )CC ) DD ORDER BY DD.userRevenueRank DESC;
